import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { HttpClientModule } from '@angular/common/http';
import { AppRoutingModule } from './app-routing.module';
import { RouterModule } from '@angular/router';
import { ReactiveFormsModule, FormsModule } from '@angular/forms';

import { AppComponent } from './app.component';
import { NavbarComponent } from './components/navbar/navbar.component';
import { SidebarComponent } from './components/components/sidebar/sidebar.component';
import { LoginComponent } from './login/login.component';
// الـ Charts
import { BaseChartDirective, provideCharts, withDefaultRegisterables } from 'ng2-charts';

// استيراد المكونات بشكل صحيح من مجلداتها الحقيقية
import { AdminDashboardComponent } from './pages/admin-dashboard/admin-dashboard.component';
import { HomeComponent } from './home/home.component';
import { AppointmentComponent } from './appointment/appointment.component';
import { AboutUsComponent } from './about-us/about-us.component';
import {ContactUsComponent} from './contact-us/contact-us.component';
import { DepartmentsComponent } from './departments/departments.component';
import { AdminPanelComponent } from './admin-panel/admin-panel.component';
import { DoctorsManagementComponent } from './doctors-management/doctors-management.component';
import { PharmacyManagementComponent } from './pharmacy-management/pharmacy-management.component';
import { LabManagementComponent } from './lab-management/lab-management.component';
import { PatientsRecordsComponent } from './patients-records/patients-records.component';
import { HospitalDepartmentsComponent } from './hospital-departments/hospital-departments.component';
import { AppointmentsComponent } from './doctor-appointments/doctor-appointments.component';

// 💡 جربي إضافة نقطتين إضافيتين ليصبح المسار هكذا للوصول لفولدر الـ services
// ... باقي الـ imports في الأعلى كما هي دون تغيير ...

@NgModule({
  declarations: [
    AppComponent,
    SidebarComponent,

  // 💡 تأكدي أنه موجود هنا في الـ declarations لأنه ليس Standalone
  ],
  imports: [
    BrowserModule,
    HttpClientModule,
    AppRoutingModule,
    ReactiveFormsModule,
    RouterModule,
    FormsModule,
    BaseChartDirective,
    LoginComponent,
    AdminPanelComponent,
    DoctorsManagementComponent,
    PharmacyManagementComponent,
    LabManagementComponent,
    HospitalDepartmentsComponent,
    // استدعاء الكومبوننتس الـ Standalone
    NavbarComponent,
    AdminDashboardComponent,
  
    HomeComponent,
AppointmentComponent,
AboutUsComponent,
ContactUsComponent,
DepartmentsComponent,
PatientsRecordsComponent,
AppointmentsComponent,
  ],
  exports: [
    SidebarComponent // 🔥 السطر ده هو السحر اللي هيحل المشكلة ويخليه مقروء بره!
  ],
  providers: [provideCharts(withDefaultRegisterables())],
  bootstrap: [AppComponent]
})
export class AppModule { }
